package com.promonts.dto;import com.promonts.domain.assignment.Assignment;import lombok.*;import java.time.LocalDateTime;@Data @NoArgsConstructor @AllArgsConstructor @Builder public class AssignmentListResponse{private Long id;private String title;private LocalDateTime dueDate;private String courseName;public static AssignmentListResponse from(Assignment assignment){return AssignmentListResponse.builder().id(assignment.getId()).title(assignment.getTitle()).dueDate(assignment.getDueDate()).courseName(assignment.getCourse().getName()).build();}}
